<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>Snake Game</title>
  <style>
    body {
      background-color: #1e1e1e;
      color: white;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      height: 100vh;
      margin: 0;
      font-family: sans-serif;
    }
    canvas {
      border: 2px solid #444;
      background-color: #2c2c2c;
    }
    button {
      margin: 5px;
      padding: 10px 20px;
      font-size: 16px;
    }
    #score {
      margin-top: 20px;
      font-size: 24px;
    }
  </style>
</head>
<body>
  <div id="score">Score: 0</div>
  <button id="start">Start</button>
  <button id="pause">Pause</button>
  <button id="reset">Reset</button>
  <canvas id="snake" width="400" height="400"></canvas>
  <script>
    (function() {
      const canvas = document.getElementById('snake');
      const ctx = canvas.getContext('2d');
      const cellSize = 40;
      let intervalId = null;

      let snake, direction, foodX, foodY, score, alive;

      function resetGame() {
        snake = [
          [5, 5],
          [5, 4],
          [5, 3]
        ];
        direction = 'right';
        placeFood();
        score = 0;
        alive = true;
        updateScoreDisplay();
        draw();
      }

      function placeFood() {
        let newFoodX, newFoodY;
        do {
          newFoodX = Math.floor(Math.random() * window.game.w);
          newFoodY = Math.floor(Math.random() * window.game.h);
        } while (snake.some(([x,y]) => x === newFoodX && y === newFoodY));
        foodX = newFoodX;
        foodY = newFoodY;
      }

      function updateScoreDisplay() {
        document.getElementById('score').textContent = 'Score: ' + score;
      }

      function draw() {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        // Draw snake
        ctx.fillStyle = '#4caf50';
        for (const [x, y] of snake) {
          ctx.fillRect(x * cellSize, y * cellSize, cellSize - 2, cellSize - 2);
        }
        // Draw food
        ctx.fillStyle = '#f44336';
        ctx.fillRect(foodX * cellSize, foodY * cellSize, cellSize - 2, cellSize - 2);
      }

      window.game = {
        w: 10,
        h: 10,
        reset() {
          resetGame();
        },
        tick() {
          if (!alive) return;
          const head = [...snake[0]];
          switch (direction) {
            case 'up': head[1] -= 1; break;
            case 'down': head[1] += 1; break;
            case 'left': head[0] -= 1; break;
            case 'right': head[0] += 1; break;
          }

          if (head[0] < 0 || head[0] >= window.game.w ||
              head[1] < 0 || head[1] >= window.game.h) {
            alive = false;
            return;
          }

          if (snake.slice(0, -1).some(([x,y]) => x === head[0] && y === head[1])) {
            alive = false;
            return;
          }

          snake.unshift(head);

          if (head[0] === foodX && head[1] === foodY) {
            score += 1;
            updateScoreDisplay();
            placeFood();
          } else {
            snake.pop();
          }

          draw();
        },
        setDir(dir) {
          const opposite = { up: 'down', down: 'up', left: 'right', right: 'left' };
          if (direction !== opposite[dir]) {
            direction = dir;
          }
        },
        setFood(x, y) {
          foodX = x;
          foodY = y;
          draw();
        },
        snake() {
          return snake.map(([x,y]) => [x, y]);
        },
        food() {
          return [foodX, foodY];
        },
        alive() {
          return alive;
        },
        score() {
          return score;
        }
      };

      resetGame();

      window.addEventListener('keydown', (e) => {
        switch(e.key) {
          case 'ArrowUp': window.game.setDir('up'); break;
          case 'ArrowDown': window.game.setDir('down'); break;
          case 'ArrowLeft': window.game.setDir('left'); break;
          case 'ArrowRight': window.game.setDir('right'); break;
        }
      });

      document.getElementById('start').addEventListener('click', () => {
        if (!intervalId) {
          intervalId = setInterval(() => {
            if (window.game.alive()) {
              window.game.tick();
            }
          }, 200);
        }
      });

      document.getElementById('pause').addEventListener('click', () => {
        clearInterval(intervalId);
        intervalId = null;
      });

      document.getElementById('reset').addEventListener('click', () => {
        clearInterval(intervalId);
        intervalId = null;
        window.game.reset();
      });
    })();
  </script>
</body>
</html>
